A binary search tree (BST) is a binary tree data structure where each node has at most two children, which are referred to as the left child and the right child. It satisfies the following properties:

1. The left subtree of a node contains only nodes with keys less than the node's key.
2. The right subtree of a node contains only nodes with keys greater than the node's key.
3. The left and right subtree each must also be a binary search tree.

Here is the code for a binary search tree with methods for insertion, deletion, and searching, as well as breadth-first search (BFS) and depth-first search (DFS).

```python
class Node:
    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None

class BinarySearchTree:
    def __init__(self):
        self.root = None

    def insert(self, key):
        if self.root is None:
            self.root = Node(key)
        else:
            self._insert(key, self.root)

    def _insert(self, key, current_node):
        if key < current_node.key:
            if current_node.left is None:
                current_node.left = Node(key)
            else:
                self._insert(key, current_node.left)
        else:
            if current_node.right is None:
                current_node.right = Node(key)
            else:
                self._insert(key, current_node.right)

    def search(self, key):
        if self.root:
            return self._search(key, self.root)
        else:
            return False

    def _search(self, key, current_node):
        if key == current_node.key:
            return True
        elif key < current_node.key and current_node.left is not None:
            return self._search(key, current_node.left)
        elif key > current_node.key and current_node.right is not None:
            return self._search(key, current_node.right)
        return False

    def delete(self, key):
        if self.root:
            self.root = self._delete(key, self.root)

    def _delete(self, key, current_node):
        if current_node is None:
            return current_node

        if key < current_node.key:
            current_node.left = self._delete(key, current_node.left)
        elif key > current_node.key:
            current_node.right = self._delete(key, current_node.right)
        else:
            if current_node.left is None:
                return current_node.right
            elif current_node.right is None:
                return current_node.left

            min_larger_node = self._find_min(current_node.right)
            current_node.key = min_larger_node.key
            current_node.right = self._delete(min_larger_node.key, current_node.right)

        return current_node

    def _find_min(self, current_node):
        while current_node.left is not None:
            current_node = current_node.left
        return current_node

    def bfs(self):
        if not self.root:
            return []

        result, queue = [], [self.root]
        while queue:
            current_node = queue.pop(0)
            if current_node.left:
                queue.append(current_node.left)
            if current_node.right:
                queue.append(current_node.right)
            result.append(current_node.key)

        return result

    def dfs_inorder(self):
        return self._dfs_inorder(self.root, [])

    def _dfs_inorder(self, current_node, visited_nodes):
        if current_node:
            visited_nodes = self._dfs_inorder(current_node.left, visited_nodes)
            visited_nodes.append(current_node.key)
            visited_nodes = self._dfs_inorder(current_node.right, visited_nodes)
        return visited_nodes

    def dfs_preorder(self):
        return self._dfs_preorder(self.root, [])

    def _dfs_preorder(self, current_node, visited_nodes):
        if current_node:
            visited_nodes.append(current_node.key)
            visited_nodes = self._dfs_preorder(current_node.left, visited_nodes)
            visited_nodes = self._dfs_preorder(current_node.right, visited_nodes)
        return visited_nodes

    def dfs_postorder(self):
        return self._dfs_postorder(self.root, [])

    def _dfs_postorder(self, current_node, visited_nodes):
        if current_node:
            visited_nodes = self._dfs_postorder(current_node.left, visited_nodes)
            visited_nodes = self._dfs_postorder(current_node.right, visited_nodes)
            visited_nodes.append(current_node.key)
        return visited_nodes

```

