In this implementation, we have a Node class representing the nodes of the tree, and a BinarySearchTree class that is the main tree where we add, search, and delete nodes.

We implemented the following traversal methods:
- Breadth-first search (BFS): It visits each node in a level-order fashion, starting from the left and going to the right.
- Depth-first search (DFS): It visits nodes in three ways:
    - In-Order: Left -> Node -> Right
    - Pre-Order: Node -> Left -> Right
    - Post-Order: Left -> Right -> Node

Here's a simpler implementation of the binary search tree without BFS and DFS but with methods to insert, search, and delete nodes.

```python
class Node:
    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None

class BinarySearchTree:
    def __init__(self):
        self.root = None

    def insert(self, key):
        if self.root is None:
            self.root = Node(key)
        else:
            self._insert(key, self.root)

    def _insert(self, key, curr):
        if key < curr.key:
            if curr.left is None:
                curr.left = Node(key)
            else:
                self._insert(key, curr.left)
        else:
            if curr.right is None:
                curr.right = Node(key)
            else:
                self._insert(key, curr.right)

    def search(self, key):
        return self._search(key, self.root)

    def _search(self, key, curr):
        if curr is None or curr.key == key:
            return curr is not None
        if key < curr.key:
            return self._search(key, curr.left)
        return self._search(key, curr.right)

    def delete(self, key):
        self.root = self._delete(key, self.root)

    def _delete(self, key, curr):
        if curr is None:
            return curr
        if key < curr.key:
            curr.left = self._delete(key, curr.left)
        elif key > curr.key:
            curr.right = self._delete(key, curr.right)
        else:
            if curr.left is None:
                return curr.right
            elif curr.right is None:
                return curr.left
            min_larger_node = self._find_min(curr.right)
            curr.key = min_larger_node.key
            curr.right = self._delete(min_larger_node.key, curr.right)
        return curr

    def _find_min(self, curr):
        if curr.left is None:
            return curr
        return self._find_min(curr.left)

