Here's a simplified version of the Tic Tac Toe game with constantly learning AI using TensorFlow:

```python
import numpy as np
import random
import tensorflow as tf
from tensorflow import keras
from tensorflow.keras import layers
import time

class TicTacToe:
    def __init__(self):
        self.board = self._create_board()

    def _create_board(self):
        return np.zeros((3, 3), dtype=int)

    def reset_board(self):
        self.board = self._create_board()

    def play(self, row, col, player):
        if self.board[row][col] == 0:
            self.board[row][col] = player
            return True
        else:
            return False

    def check_winner(self, player):
        for row in range(3):
            if all(cell == player for cell in self.board[row, :]):
                return True
        for col in range(3):
            if all(cell == player for cell in self.board[:, col]):
                return True
        if all(self.board[i, i] == player for i in range(3)):
            return True
        if all(self.board[i, 2 - i] == player for i in range(3)):
            return True
        return False

    def is_full(self):
        return not any(0 in row for row in self.board)

def build_model():
    model = keras.Sequential([
        layers.Dense(9, activation="relu", input_shape=(9,)),
        layers.Dense(18, activation="relu"),
        layers.Dense(9, activation="softmax")
    ])

    model.compile(optimizer=keras.optimizers.Adam(0.001),
                  loss="sparse_categorical_crossentropy",
                  metrics=["accuracy"])
    return model

def play_AI(game, model):
    board_state = game.board.flatten()
    predictions = model.predict(board_state.reshape(1, -1))
    best_move = np.argmax(predictions)
    row, col = divmod(best_move, 3)

    if game.play(row, col, -1):
        return True, game, best_move

    return False, game, best_move

def play_game():
    game = TicTacToe()
    training_data = []
    model = build_model()

    while True:
        game.reset_board()
        print("\nNew Game:")
        print(game.board)

        while True:
            row, col = map(int, input("Enter row and column (0-2) separated by space: ").split())
            if game.play(row, col, 1):
                training_data.append((game.board.copy(), (row, col)))
                print(game.board)

                if game.check_winner(1):
                    move_values = [-1 if move[1] == (row, col) else 0 for move in training_data]
                    train_model(model, training_data, move_values)

                    print("You won!")
                    break

                if game.is_full():
                    print("It's a draw!")
                    break

                valid_move, game, best_move = False, game, None
                while not valid_move:
                    valid_move, new_game, new_best_move = play_AI(game, model)
                    if not valid_move:
                        game.play(random.randint(0, 2), random.randint(0, 2), -1)
                    else:
                        best_move = new_best_move

                training_data.append((game.board.copy(), best_move))
                print("AI moved:")
                print(game.board)

                if game.check_winner(-1):
                    move_values = [-1 if move[1] == best_move else 0 for move in training_data]
                    train_model(model, training_data, move_values)

                    print("AI won!")
                    break

def train_model(model, training_data, move_values):
    print("Training AI...")
    X = np.asarray([data[0].flatten() for data in training_data])
    y = np.asarray([3 * move[0] + move[1] for move in move_values])

    model.fit(X, y, epochs=20, verbose=0)

if __name__ == "__main__":
    play_game()
```

Please note that the AI's learning ability can still be improved, and this code is meant to demonstrate a basic implementation of Tic Tac Toe with AI learning.
